using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Label")]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly ILogger<TicketModelTrainer> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger, string dataPath, string modelPath)
    {
        _logger = logger;
        _dataPath = dataPath;
        _modelPath = modelPath;
    }

    public void TrainAndSaveModel()
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.3);

        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("Model evaluation metrics:");
        _logger.LogInformation("  MacroAccuracy: {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  LogLoss:       {LogLoss:F4}", metrics.LogLoss);

        foreach (var classMetric in metrics.PerClassLogLoss.Select((value, index) => (value, index)))
        {
            _logger.LogInformation("  Class {Index} LogLoss: {LogLoss:F4}", classMetric.index, classMetric.value);
        }

        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public IActionResult Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        // Get label names from the model's label buffer
        var labelNames = GetLabelNames();
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < labelNames.Length; i++)
        {
            confidence[labelNames[i]] = prediction.Score[i];
        }

        return Ok(new
        {
            category = prediction.PredictedLabel,
            confidence
        });
    }

    private string[] GetLabelNames()
    {
        var modelPath = Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "Data", "ticket-model.zip");
        if (!System.IO.File.Exists(modelPath))
        {
            modelPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "ticket-model.zip");
        }

        var mlContext = new MLContext();
        var model = mlContext.Model.Load(modelPath, out _);

        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        model.GetOutputSchema(SchemaDefinition.Create(typeof(TicketData)))
            .GetColumnOrNull("Score")?.GetSlotNames(ref labelBuffer);

        if (labelBuffer.Length == 0)
        {
            // Fallback: try from PredictedLabel column metadata
            model.GetOutputSchema(SchemaDefinition.Create(typeof(TicketData)))
                .GetColumnOrNull("PredictedLabel")?.GetKeyValues(ref labelBuffer);
        }

        return labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    }
}

public class ClassifyRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public float Priority { get; set; }
}

