1. using Microsoft.AspNetCore.Mvc;
2. using Microsoft.Extensions.ML;
3. using Microsoft.ML;
4. using Microsoft.ML.Data;
5. using TicketClassifier.Models;
6. 
7. namespace TicketClassifier.Controllers;
8. 
9. [ApiController]
10. [Route("api/tickets")]
11. public class TicketController : ControllerBase
12. {
13.     private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
14. 
15.     public TicketController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
16.     {
17.         _predictionPool = predictionPool;
18.     }
19. 
20.     [HttpPost("classify")]
21.     public IActionResult Classify([FromBody] ClassifyRequest request)
22.     {
23.         var input = new TicketData
24.         {
25.             Subject = request.Subject,
26.             Description = request.Description,
27.             Priority = request.Priority
28.         };
29. 
30.         var prediction = _predictionPool.Predict(input);
31. 
32.         // Get label names from the model's label buffer
33.         var labelNames = GetLabelNames();
34.         var confidence = new Dictionary<string, float>();
35.         for (int i = 0; i < prediction.Score.Length && i < labelNames.Length; i++)
36.         {
37.             confidence[labelNames[i]] = prediction.Score[i];
38.         }
39. 
40.         return Ok(new
41.         {
42.             category = prediction.PredictedLabel,
43.             confidence
44.         });
45.     }
46. 
