    public TicketController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        LabelMap labelMap)
    {
        _predictionPool = predictionPool;
        _labelNames = labelMap.Names;
    }

    [HttpPost("classify")]
    public IActionResult Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _labelNames.Length; i++)
        {
            confidence[_labelNames[i]] = prediction.Score[i];
        }

        return Ok(new
        {
            category = prediction.PredictedLabel,
            confidence
        });
    }
}

/// <summary>Cached label names extracted from the trained model.</summary>
public class LabelMap
{
    public string[] Names { get; }

    public LabelMap(string modelPath)
    {
        var mlContext = new MLContext();
        var model = mlContext.Model.Load(modelPath, out var inputSchema);
        var outputSchema = model.GetOutputSchema(inputSchema);
        var scoreColumn = outputSchema.GetColumnOrNull("Score");

        if (scoreColumn is null)
        {
            Names = [];
            return;
        }

        var buffer = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.Value.GetSlotNames(ref buffer);
        Names = buffer.DenseValues().Select(v => v.ToString()).ToArray();
    }
}

public class ClassifyRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public float Priority { get; set; }
}

