toolArgs.new_str:
using Microsoft.Extensions.ML;
using TicketClassifier.Controllers;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ticket-model.zip");

Directory.CreateDirectory(Path.GetDirectoryName(modelPath)!);

// Train model before registering services that depend on the .zip
var trainerLogger = LoggerFactory.Create(b => b.AddConsole())
    .CreateLogger<TicketModelTrainer>();
var trainer = new TicketModelTrainer(trainerLogger, dataPath, modelPath);
trainer.TrainAndSaveModel();

// Register label map singleton (loaded once from the trained model)
builder.Services.AddSingleton(new LabelMap(modelPath));

// Register PredictionEnginePool from the trained model file
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

